    vector<pair<Int64, Int64>> elements;
    for (int i = 0; i < n; ++i) {
        elements.push_back({value[i], limit[i]});
    }

    // Sort elements by value in descending order
    sort(elements.begin(), elements.end(), [](pair<Int64, Int64> a, pair<Int64, Int64> b) {
        return a.first > b.first;
    });

    int activeCount = 0;
    int total = 0;
    vector<bool> isActive(n, false);

    for (int i = 0; i < n; ++i) {
        // Find the element with the highest value that can be activated
        int bestIdx = -1;
        for (int j = 0; j < n; ++j) {
            if (!isActive[j] && elements[j].second > activeCount) {
                bestIdx = j;
                break;
            }
        }

        if (bestIdx == -1) {
            continue;
        }

        // Activate the best element
        isActive[bestIdx] = true;
        total += elements[bestIdx].first;
        activeCount++;

        // Deactivate all elements whose limit is <= activeCount
        for (int j = 0; j < n; ++j) {
            if (!isActive[j] && elements[j].second <= activeCount) {
                isActive[j] = true;
            }
        }
    }

    return total;
}
