    // Sort the elements based on their value in descending order
    let sortedIndices = value.enumerated().sorted { $0.element > $1.element }.map { $0.0 }

    var activeCount = 0
    var totalSum = 0
    var inactiveSet = Set<Int>()

    for i in sortedIndices {
        // Check if the element can be activated
        if activeCount < limit[i] && !inactiveSet.contains(i) {
            // Activate the element
            totalSum += value[i]
            activeCount += 1

